// WF99 converts one n8n Error Trigger event into a minimal,
// sanitized canonical structure.
//
// Raw workflow input, stack traces, headers, credentials,
// request bodies, provider responses, and execution URLs
// must not leave this node.

const inputItems = $input.all();

if (inputItems.length !== 1) {
  throw new Error(
    `WF99 Error Trigger expected exactly one item, received ${inputItems.length}`,
  );
}

const source = inputItems[0].json ?? {};

const execution =
  source.execution && typeof source.execution === 'object'
    ? source.execution
    : {};

const workflow =
  source.workflow && typeof source.workflow === 'object'
    ? source.workflow
    : {};

const receivedError = execution.error ?? source.error ?? {};

const rawError =
  receivedError && typeof receivedError === 'object'
    ? receivedError
    : {
        message: receivedError,
      };

/**
 * Remove common credential and bearer-token patterns.
 */
function redactSecrets(value) {
  return value
    .replace(
      /\bBearer\s+[A-Za-z0-9\-._~+/]+=*/gi,
      'Bearer [REDACTED]',
    )
    .replace(
      /((?:authorization|cookie|set-cookie|password|passwd|secret|api[-_ ]?key|access[-_ ]?token|refresh[-_ ]?token)\s*[:=]\s*)("[^"]*"|'[^']*'|[^\s,;]+)/gi,
      '$1[REDACTED]',
    )
    .replace(
      /([?&](?:token|access_token|refresh_token|api_key|key)=)[^&\s]+/gi,
      '$1[REDACTED]',
    );
}

/**
 * Convert an optional value into bounded, sanitized,
 * single-line text.
 */
function safeText(value, maxLength) {
  if (value === null || value === undefined) {
    return null;
  }

  const normalized = redactSecrets(String(value))
    .replace(
      /[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g,
      ' ',
    )
    .replace(/\s+/g, ' ')
    .trim();

  if (!normalized) {
    return null;
  }

  return normalized.slice(0, maxLength);
}

const sourceWorkflowName =
  safeText(workflow.name, 200) ?? 'unknown_workflow';

const errorMessage =
  safeText(
    rawError.message ??
      rawError.description ??
      rawError.reason ??
      receivedError,
    1000,
  ) ?? 'Unknown workflow failure';

return [
  {
    json: {
      source_variant: 'n8n_error_trigger',

      source_workflow_name: sourceWorkflowName,
      source_workflow_id: safeText(workflow.id, 120),
      source_execution_id: safeText(execution.id, 120),

      execution_url_present:
        typeof execution.url === 'string' &&
        execution.url.trim().length > 0,

      error_name: safeText(rawError.name, 120),
      error_code: safeText(
        rawError.code ??
          rawError.errorCode ??
          rawError.httpCode ??
          rawError.statusCode,
        120,
      ),
      error_message: errorMessage,

      node_name: safeText(
        execution.lastNodeExecuted,
        200,
      ),

      case_id: null,
      step_id: null,
      submission_id: null,
      external_operation_id: null,
      correlation_id: null,

      occurred_at: new Date().toISOString(),
    },
  },
];

// WF99 validates and sanitizes trusted internal workflow calls.
// Only two variants are accepted:
// - explicit_internal
// - notification_retry

const items = $input.all();

if (items.length !== 1) {
  throw new Error(
    `WF99 internal invocation expected exactly one item, received ${items.length}`,
  );
}

const rawInput = items[0].json ?? {};

const input =
  rawInput.body &&
  typeof rawInput.body === 'object' &&
  !Array.isArray(rawInput.body)
    ? rawInput.body
    : rawInput;

function assertPlainObject(value, fieldName) {
  if (
    value === null ||
    typeof value !== 'object' ||
    Array.isArray(value)
  ) {
    throw new Error(`${fieldName} must be a JSON object`);
  }
}

assertPlainObject(input, 'input');

function rejectUnknownFields(object, allowedFields) {
  const unknownFields = Object.keys(object).filter(
    (key) => !allowedFields.has(key),
  );

  if (unknownFields.length > 0) {
    throw new Error(
      `Unknown top-level fields: ${unknownFields.join(', ')}`,
    );
  }
}

function redactSecrets(value) {
  return value
    .replace(
      /\bBearer\s+[A-Za-z0-9\-._~+/]+=*/gi,
      'Bearer [REDACTED]',
    )
    .replace(
      /((?:authorization|cookie|set-cookie|password|passwd|secret|api[-_ ]?key|access[-_ ]?token|refresh[-_ ]?token)\s*[:=]\s*)("[^"]*"|'[^']*'|[^\s,;]+)/gi,
      '$1[REDACTED]',
    )
    .replace(
      /([?&](?:token|access_token|refresh_token|api_key|key)=)[^&\s]+/gi,
      '$1[REDACTED]',
    );
}

function safeText(value, maxLength, required = false) {
  if (value === null || value === undefined) {
    if (required) {
      throw new Error('Required text value is missing');
    }

    return null;
  }

  const normalized = redactSecrets(String(value))
    .replace(
      /[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g,
      ' ',
    )
    .replace(/\s+/g, ' ')
    .trim();

  if (!normalized) {
    if (required) {
      throw new Error('Required text value is blank');
    }

    return null;
  }

  return normalized.slice(0, maxLength);
}

function optionalUuid(value, fieldName) {
  if (value === null || value === undefined) {
    return null;
  }

  if (typeof value !== 'string') {
    throw new Error(`${fieldName} must be a UUID string or null`);
  }

  const normalized = value.trim().toLowerCase();

  const uuidPattern =
    /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/;

  if (!uuidPattern.test(normalized)) {
    throw new Error(`${fieldName} must contain a valid UUID`);
  }

  return normalized;
}

const blockedDetailKeyPattern =
  /authorization|cookie|password|passwd|secret|token|api.?key|credential|header|request.?body|response.?body|stack/i;

function sanitizeDetails(value, depth = 0) {
  if (depth > 2) {
    return '[TRUNCATED]';
  }

  if (
    value === null ||
    typeof value === 'boolean' ||
    typeof value === 'number'
  ) {
    return value;
  }

  if (typeof value === 'string') {
    return safeText(value, 500);
  }

  if (Array.isArray(value)) {
    return value
      .slice(0, 20)
      .map((entry) => sanitizeDetails(entry, depth + 1));
  }

  if (typeof value === 'object') {
    const result = {};

    for (const [key, entry] of Object.entries(value).slice(0, 20)) {
      if (blockedDetailKeyPattern.test(key)) {
        result[key] = '[REDACTED]';
        continue;
      }

      result[key] = sanitizeDetails(entry, depth + 1);
    }

    return result;
  }

  return safeText(value, 500);
}

const sourceVariant = safeText(
  input.source_variant,
  80,
  true,
);

if (sourceVariant === 'notification_retry') {
  const allowedFields = new Set([
    'source_variant',
    'trigger_source',
    'external_operation_id',
  ]);

  rejectUnknownFields(input, allowedFields);

  if (input.trigger_source !== 'wf98') {
    throw new Error(
      'notification_retry trigger_source must equal wf98',
    );
  }

  return [
    {
      json: {
        source_variant: 'notification_retry',
        trigger_source: 'wf98',
        external_operation_id: optionalUuid(
          input.external_operation_id,
          'external_operation_id',
        ),
      },
    },
  ];
}

if (sourceVariant !== 'explicit_internal') {
  throw new Error(
    `Unsupported source_variant: ${sourceVariant}`,
  );
}

const allowedFields = new Set([
  'source_variant',
  'source_workflow_name',
  'source_workflow_id',
  'source_execution_id',
  'case_id',
  'correlation_id',
  'step_id',
  'submission_id',
  'external_operation_id',
  'error_class',
  'error_code',
  'error_message',
  'retryable',
  'severity',
  'requires_intervention',
  'error_details',
]);

rejectUnknownFields(input, allowedFields);

if (typeof input.retryable !== 'boolean') {
  throw new Error('retryable must be boolean');
}

if (typeof input.requires_intervention !== 'boolean') {
  throw new Error('requires_intervention must be boolean');
}

const allowedSeverities = new Set([
  'warning',
  'error',
  'critical',
]);

if (!allowedSeverities.has(input.severity)) {
  throw new Error(
    'severity must be warning, error, or critical',
  );
}

if (
  input.error_details !== null &&
  input.error_details !== undefined
) {
  assertPlainObject(input.error_details, 'error_details');
}

return [
  {
    json: {
      source_variant: 'explicit_internal',

      source_workflow_name: safeText(
        input.source_workflow_name,
        200,
        true,
      ),
      source_workflow_id: safeText(
        input.source_workflow_id,
        120,
      ),
      source_execution_id: safeText(
        input.source_execution_id,
        120,
      ),

      case_id: optionalUuid(input.case_id, 'case_id'),
      correlation_id: optionalUuid(
        input.correlation_id,
        'correlation_id',
      ),
      step_id: optionalUuid(input.step_id, 'step_id'),
      submission_id: optionalUuid(
        input.submission_id,
        'submission_id',
      ),
      external_operation_id: optionalUuid(
        input.external_operation_id,
        'external_operation_id',
      ),

      error_class: safeText(
        input.error_class,
        120,
        true,
      ),
      error_code: safeText(input.error_code, 120),
      error_message: safeText(
        input.error_message,
        1000,
        true,
      ),

      retryable: input.retryable,
      severity: input.severity,
      requires_intervention:
        input.requires_intervention,

      error_details: sanitizeDetails(
        input.error_details ?? {},
      ),

      occurred_at: new Date().toISOString(),
    },
  },
];

// WF99 derives a conservative technical-error classification
// from the already sanitized n8n Error Trigger structure.
//
// Unknown errors are never marked retryable optimistically.

const items = $input.all();

if (items.length !== 1) {
  throw new Error(
    `WF99 classification expected exactly one item, received ${items.length}`,
  );
}

const input = items[0].json ?? {};

if (input.source_variant !== 'n8n_error_trigger') {
  throw new Error(
    'Classify Error Trigger Failure accepts only n8n_error_trigger input',
  );
}

const combined = [
  input.error_name,
  input.error_code,
  input.error_message,
  input.node_name,
]
  .filter((value) => value !== null && value !== undefined)
  .join(' ')
  .toLowerCase();

let errorClass = 'unknown_failure';
let retryable = false;
let severity = 'error';
let requiresIntervention = true;

/**
 * Authentication and authorization failures require configuration
 * or permission correction and must not be retried automatically.
 */
if (
  /\b401\b|unauthenticated|authentication failed|invalid credential|invalid oauth|token expired/.test(
    combined,
  )
) {
  errorClass = 'authentication_failure';
  retryable = false;
  severity = 'critical';
  requiresIntervention = true;
} else if (
  /\b403\b|forbidden|permission denied|not authorized|insufficient permission/.test(
    combined,
  )
) {
  errorClass = 'authorization_failure';
  retryable = false;
  severity = 'critical';
  requiresIntervention = true;
} else if (
  /configuration|misconfigured|missing credential|missing environment|invalid configuration/.test(
    combined,
  )
) {
  errorClass = 'configuration_failure';
  retryable = false;
  severity = 'critical';
  requiresIntervention = true;
} else if (
  /data integrity|foreign key|constraint violation|correlation mismatch|persisted-data inconsistency/.test(
    combined,
  )
) {
  errorClass = 'data_integrity_failure';
  retryable = false;
  severity = 'critical';
  requiresIntervention = true;
} else if (
  /idempotency|duplicate logical operation|different operation/.test(
    combined,
  )
) {
  errorClass = 'idempotency_conflict';
  retryable = false;
  severity = 'critical';
  requiresIntervention = true;
} else if (
  /decrypt|authentication tag|secret exposure|security policy|token material/.test(
    combined,
  )
) {
  errorClass = 'security_failure';
  retryable = false;
  severity = 'critical';
  requiresIntervention = true;
} else if (
  /ambiguous|multiple matching|reconciliation failed|duplicate external side effect/.test(
    combined,
  )
) {
  errorClass = 'reconciliation_failure';
  retryable = false;
  severity = 'critical';
  requiresIntervention = true;
} else if (
  /\b429\b|rate limit|too many requests/.test(combined)
) {
  errorClass = 'rate_limit_failure';
  retryable = true;
  severity = 'warning';
  requiresIntervention = false;
} else if (
  /timeout|timed out|etimedout|\b504\b/.test(combined)
) {
  errorClass = 'timeout_failure';
  retryable = true;
  severity = 'warning';
  requiresIntervention = false;
} else if (
  /econnreset|econnrefused|enotfound|dns|network|socket hang up|connection closed/.test(
    combined,
  )
) {
  errorClass = 'network_failure';
  retryable = true;
  severity = 'warning';
  requiresIntervention = false;
} else if (
  /\b502\b|\b503\b|temporarily unavailable|service unavailable|provider unavailable/.test(
    combined,
  )
) {
  errorClass = 'integration_failure';
  retryable = true;
  severity = 'warning';
  requiresIntervention = false;
} else if (
  /postgres|database|sql|connection pool/.test(combined)
) {
  errorClass = 'database_failure';
  retryable = true;
  severity = 'error';
  requiresIntervention = false;
} else if (
  /dispatch|sub-workflow|queue|could not start workflow/.test(
    combined,
  )
) {
  errorClass = 'dispatch_failure';
  retryable = true;
  severity = 'warning';
  requiresIntervention = false;
} else if (
  /workflow|node execution|execution failed/.test(combined)
) {
  errorClass = 'workflow_failure';
  retryable = false;
  severity = 'error';
  requiresIntervention = true;
}

const errorDetails = {
  node_name: input.node_name ?? null,
  provider_error_code: input.error_code ?? null,
  source_variant: 'n8n_error_trigger',
  requires_intervention: requiresIntervention,
};

return [
  {
    json: {
      source_variant: 'n8n_error_trigger',

      source_workflow_name:
        input.source_workflow_name ?? 'unknown_workflow',
      source_workflow_id:
        input.source_workflow_id ?? null,
      source_execution_id:
        input.source_execution_id ?? null,

      execution_url_present:
        input.execution_url_present === true,

      case_id: input.case_id ?? null,
      correlation_id: input.correlation_id ?? null,
      step_id: input.step_id ?? null,
      submission_id: input.submission_id ?? null,
      external_operation_id:
        input.external_operation_id ?? null,

      error_class: errorClass,
      error_code: input.error_code ?? null,
      error_message:
        input.error_message ?? 'Unknown workflow failure',

      retryable,
      severity,
      requires_intervention: requiresIntervention,
      error_details: errorDetails,

      occurred_at:
        input.occurred_at ?? new Date().toISOString(),
    },
  },
];

const input = $json;

const requiredFields = [
  'notification_operation_id',
  'recipient_email',
  'message_marker',
  'error_id',
  'source_workflow_name',
  'error_class',
  'error_message',
  'severity',
  'occurred_at',
];

for (const field of requiredFields) {
  const value = input[field];

  if (value === null || value === undefined || String(value).trim() === '') {
    throw new Error(`Missing required notification field: ${field}`);
  }
}

const recipientEmail = String(input.recipient_email).trim();

if (
  !/^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i.test(
    recipientEmail
  )
) {
  throw new Error('Invalid operator notification recipient email');
}

const displayValue = (value) => {
  if (value === null || value === undefined || value === '') {
    return 'Not provided';
  }

  return String(value);
};

const escapeHtml = (value) => {
  return displayValue(value)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
};

const severity = String(input.severity).toUpperCase();

const subject =
  `[${severity}] B2B onboarding operator intervention required`;

const textBody = [
  'A B2B onboarding workflow requires operator intervention.',
  '',
  `Severity: ${severity}`,
  `Source workflow: ${displayValue(input.source_workflow_name)}`,
  `Error class: ${displayValue(input.error_class)}`,
  `Error code: ${displayValue(input.error_code)}`,
  `Error message: ${displayValue(input.error_message)}`,
  `Occurred at: ${displayValue(input.occurred_at)}`,
  '',
  `Case ID: ${displayValue(input.case_id)}`,
  `Correlation ID: ${displayValue(input.correlation_id)}`,
  `Source operation ID: ${displayValue(
    input.source_external_operation_id
  )}`,
  '',
  `Error ID: ${displayValue(input.error_id)}`,
  `Notification operation ID: ${displayValue(
    input.notification_operation_id
  )}`,
  `Notification attempt: ${displayValue(
    input.notification_attempt_count
  )}/${displayValue(input.notification_max_attempts)}`,
  '',
  `Message marker: ${displayValue(input.message_marker)}`,
].join('\n');

const htmlBody = `
<div style="font-family: Arial, sans-serif; line-height: 1.5;">
  <h2>B2B onboarding operator intervention required</h2>

  <table cellpadding="6" cellspacing="0" border="0">
    <tr>
      <td><strong>Severity</strong></td>
      <td>${escapeHtml(severity)}</td>
    </tr>
    <tr>
      <td><strong>Source workflow</strong></td>
      <td>${escapeHtml(input.source_workflow_name)}</td>
    </tr>
    <tr>
      <td><strong>Error class</strong></td>
      <td>${escapeHtml(input.error_class)}</td>
    </tr>
    <tr>
      <td><strong>Error code</strong></td>
      <td>${escapeHtml(input.error_code)}</td>
    </tr>
    <tr>
      <td><strong>Error message</strong></td>
      <td>${escapeHtml(input.error_message)}</td>
    </tr>
    <tr>
      <td><strong>Occurred at</strong></td>
      <td>${escapeHtml(input.occurred_at)}</td>
    </tr>
    <tr>
      <td><strong>Case ID</strong></td>
      <td>${escapeHtml(input.case_id)}</td>
    </tr>
    <tr>
      <td><strong>Correlation ID</strong></td>
      <td>${escapeHtml(input.correlation_id)}</td>
    </tr>
    <tr>
      <td><strong>Source operation ID</strong></td>
      <td>${escapeHtml(input.source_external_operation_id)}</td>
    </tr>
    <tr>
      <td><strong>Error ID</strong></td>
      <td>${escapeHtml(input.error_id)}</td>
    </tr>
    <tr>
      <td><strong>Notification operation ID</strong></td>
      <td>${escapeHtml(input.notification_operation_id)}</td>
    </tr>
    <tr>
      <td><strong>Notification attempt</strong></td>
      <td>${escapeHtml(
        input.notification_attempt_count
      )}/${escapeHtml(input.notification_max_attempts)}</td>
    </tr>
  </table>

  <p style="font-size: 12px; color: #666;">
    ${escapeHtml(input.message_marker)}
  </p>
</div>
`.trim();

return {
  json: {
    ...input,
    recipient_email: recipientEmail,
    email_subject: subject,
    email_text: textBody,
    email_html: htmlBody,
  },
};

const input = $json;

const error =
  input.error && typeof input.error === 'object'
    ? input.error
    : {};

const cause =
  error.cause && typeof error.cause === 'object'
    ? error.cause
    : {};

function firstNonEmpty(...values) {
  for (const value of values) {
    if (value === null || value === undefined) {
      continue;
    }

    const text = String(value).trim();

    if (text !== '') {
      return text;
    }
  }

  return null;
}

function redactSecrets(value) {
  if (!value) {
    return null;
  }

  return String(value)
    .replace(
      /(authorization:\s*bearer\s+)[^\s]+/gi,
      '$1[REDACTED]'
    )
    .replace(
      /((?:access|refresh|id)_token["'\s:=]+)[^\s,"'}]+/gi,
      '$1[REDACTED]'
    )
    .replace(
      /(client_secret["'\s:=]+)[^\s,"'}]+/gi,
      '$1[REDACTED]'
    )
    .slice(0, 1000);
}

const rawStatusCode = firstNonEmpty(
  error.httpCode,
  error.statusCode,
  error.status,
  cause.httpCode,
  cause.statusCode,
  cause.status,
  input.httpCode,
  input.statusCode
);

const parsedStatusCode = Number(rawStatusCode);

const statusCode =
  Number.isInteger(parsedStatusCode) &&
  parsedStatusCode >= 100 &&
  parsedStatusCode <= 599
    ? parsedStatusCode
    : null;

const rawMessage = firstNonEmpty(
  error.message,
  error.description,
  cause.message,
  cause.description,
  input.message,
  'Gmail notification delivery failed'
);

const errorMessage =
  redactSecrets(rawMessage) ??
  'Gmail notification delivery failed';

const searchableText = [
  error.name,
  error.code,
  error.message,
  error.description,
  cause.name,
  cause.code,
  cause.message,
  cause.description
]
  .filter(value => value !== null && value !== undefined)
  .join(' ')
  .toLowerCase();

const isAuthenticationFailure =
  statusCode === 401 ||
  searchableText.includes('invalid_grant') ||
  searchableText.includes('unauthenticated') ||
  searchableText.includes('invalid credential') ||
  searchableText.includes('authentication failed');

const isAuthorizationFailure =
  statusCode === 403 ||
  searchableText.includes('permission denied') ||
  searchableText.includes('permission_denied') ||
  searchableText.includes('forbidden') ||
  searchableText.includes('insufficient permission');

const isRateLimitFailure =
  statusCode === 429 ||
  searchableText.includes('rate limit') ||
  searchableText.includes('rate_limit') ||
  searchableText.includes('quota exceeded') ||
  searchableText.includes('too many requests');

const isTimeoutFailure =
  statusCode === 408 ||
  searchableText.includes('timeout') ||
  searchableText.includes('timed out') ||
  searchableText.includes('etimedout') ||
  searchableText.includes('socket hang up');

const isNetworkFailure =
  searchableText.includes('econnreset') ||
  searchableText.includes('econnrefused') ||
  searchableText.includes('enotfound') ||
  searchableText.includes('network error') ||
  searchableText.includes('connection reset');

const isProviderFailure =
  statusCode !== null &&
  statusCode >= 500 &&
  statusCode <= 599;

let failureClass = 'notification_delivery_failure';
let transportRetryable = false;

if (isAuthenticationFailure) {
  failureClass = 'authentication_failure';
} else if (isAuthorizationFailure) {
  failureClass = 'authorization_failure';
} else if (isRateLimitFailure) {
  failureClass = 'rate_limit_failure';
  transportRetryable = true;
} else if (isTimeoutFailure) {
  failureClass = 'timeout_failure';
  transportRetryable = true;
} else if (isNetworkFailure) {
  failureClass = 'integration_failure';
  transportRetryable = true;
} else if (isProviderFailure) {
  failureClass = 'provider_failure';
  transportRetryable = true;
}

const attemptCount = Number(
  input.notification_attempt_count ?? 0
);

const maxAttempts = Number(
  input.notification_max_attempts ?? 1
);

const retryAllowed =
  transportRetryable &&
  attemptCount < maxAttempts;

// 5, 10, 20, 40, then maximum 60 minutes.
const retryDelayMinutes = Math.min(
  5 * Math.pow(
    2,
    Math.max(attemptCount - 1, 0)
  ),
  60
);

const nextRetryAt = retryAllowed
  ? new Date(
      Date.now() + retryDelayMinutes * 60 * 1000
    ).toISOString()
  : null;

return {
  json: {
    ...input,

    notification_failure_class: failureClass,
    notification_failure_message: errorMessage,
    notification_failure_status_code: statusCode,

    notification_failure_retryable: retryAllowed,
    notification_next_retry_at: nextRetryAt,

    notification_failure_summary: {
      provider: 'gmail',
      failure_class: failureClass,
      status_code: statusCode,
      message: errorMessage,
      attempt_count: attemptCount,
      max_attempts: maxAttempts,
      retry_allowed: retryAllowed,
      message_marker:
        input.message_marker ?? null
    }
  }
};

const input = $json;

const leaseOwned =
  typeof input.lease_owned === 'boolean'
    ? input.lease_owned
    : null;

const operationStatus =
  input.notification_operation_status ??
  input.operation_status ??
  null;

let outcome = String(
  input.notification_claim_outcome ?? ''
).trim();

if (outcome === '' && leaseOwned === false) {
  outcome = 'lease_not_owned';
}

if (outcome === '') {
  outcome = 'unexpected';
}

let handlerStatus;
let completed;
let deferred;
let failureReason = null;
let notificationSent = false;

if (leaseOwned === false) {
  if (operationStatus === 'succeeded') {
    handlerStatus = 'completed';
    completed = true;
    deferred = false;
    notificationSent = true;
  } else if (operationStatus === 'failed_terminal') {
    handlerStatus = 'failed_terminal';
    completed = false;
    deferred = false;
    failureReason = 'notification_operation_terminal';
  } else {
    handlerStatus = 'deferred';
    completed = false;
    deferred = true;
    failureReason = 'notification_lease_not_owned';
  }
} else {
  switch (outcome) {
    case 'reuse_succeeded':
      handlerStatus = 'completed';
      completed = true;
      deferred = false;
      notificationSent = true;
      break;

    case 'not_required':
      handlerStatus = 'completed';
      completed = true;
      deferred = false;
      break;

    case 'busy':
      handlerStatus = 'deferred';
      completed = false;
      deferred = true;
      break;

    case 'not_due':
      handlerStatus = 'deferred';
      completed = false;
      deferred = true;
      break;

    case 'refused_terminal':
      handlerStatus = 'failed_terminal';
      completed = false;
      deferred = false;
      failureReason = 'notification_operation_terminal';
      break;

    case 'refused_exhausted':
      handlerStatus = 'failed_terminal';
      completed = false;
      deferred = false;
      failureReason = 'notification_attempts_exhausted';
      break;

    case 'configuration_invalid':
      handlerStatus = 'failed_terminal';
      completed = false;
      deferred = false;
      failureReason =
        'notification_configuration_invalid';
      break;

    case 'operation_not_found':
      handlerStatus = 'failed_terminal';
      completed = false;
      deferred = false;
      failureReason =
        'notification_operation_not_found';
      break;

    default:
      handlerStatus = 'unexpected';
      completed = false;
      deferred = false;
      failureReason =
        'unexpected_notification_claim_outcome';
      break;
  }
}

const notificationRequired =
  typeof input.requires_intervention === 'boolean'
    ? input.requires_intervention
    : input.notification_operation_id !== null &&
      input.notification_operation_id !== undefined;

return {
  json: {
    workflow_name: 'WF99 — Central Error Handler',

    handler_status: handlerStatus,
    handler_completed: completed,
    handler_deferred: deferred,

    error_id: input.error_id ?? null,
    error_class: input.error_class ?? null,
    severity: input.severity ?? null,

    notification_required: notificationRequired,
    notification_sent: notificationSent,

    notification_claim_outcome: outcome,

    notification_operation_id:
      input.notification_operation_id ?? null,

    notification_operation_status:
      operationStatus,

    notification_attempt_count:
      input.notification_attempt_count ?? null,

    notification_lease_expires_at:
      input.notification_lease_expires_at ??
      input.lease_expires_at ??
      null,

    failure_reason: failureReason
  }
};
